MATCH (p:Program)
WHERE p.ten_chuong_trinh CONTAINS "Kỹ thuật Công trình thủy K2016"
RETURN p.ten_chuong_trinh AS ProgramName, p.ngon_ngu AS Language;

MATCH (p:Program)
WHERE p.ten_chuong_trinh CONTAINS "Quản lý Tài nguyên và môi trường K2020"
RETURN p.ten_chuong_trinh AS ProgramName, p.ngon_ngu AS Language;

MATCH (p:Program {ten_chuong_trinh: "Kỹ thuật Điện K2021CLC_kỹ sư"})-[:HAS_SEMESTER]->(sem:Semester)-[:HAS_SUBJECT]->(s:Subject {ten_hoc_phan: "Đồ án tốt nghiệp"})
MATCH (prereq:Subject)-[:PREREQUISITE_OF]->(s)
RETURN prereq.ma_hp AS MaHocPhan, prereq.ten_hoc_phan AS TenHocPhan;
